import gurobipy as gp
from gurobipy import GRB

def solve_transportation_problem(Cities, Links, Products, Supply, Demand, ShipmentCost, Capacity, JointCapacity):
    # Create model
    model = gp.Model("MultiProductTransportation")

    # Create decision variables: x[i,j,p] = units of product p shipped from i to j
    x = model.addVars(
        [(i, j, p) for i, j in Links for p in Products],
        vtype=GRB.INTEGER,
        name="x"
    )

    # Set objective: minimize total shipping cost
    model.setObjective(
        gp.quicksum(ShipmentCost[i, j, p] * x[i, j, p] for i, j in Links for p in Products),
        GRB.MINIMIZE
    )

    # Add supply constraints
    for i in Cities:
        for p_idx, p in enumerate(Products):
            model.addConstr(
                gp.quicksum(x[i, j, p] for j in Cities if (i, j) in Links) <= Supply[Cities.index(i)][p_idx],
                name=f"Supply_{i}_{p}"
            )

    # Add demand constraints
    for j in Cities:
        for p_idx, p in enumerate(Products):
            model.addConstr(
                gp.quicksum(x[i, j, p] for i in Cities if (i, j) in Links) >= Demand[Cities.index(j)][p_idx],
                name=f"Demand_{j}_{p}"
            )

    # Add product capacity constraints
    for i, j in Links:
        for p in Products:
            model.addConstr(
                x[i, j, p] <= Capacity[i, j, p],
                name=f"ProdCapacity_{i}_{j}_{p}"
            )

    # Add joint capacity constraints
    for i, j in Links:
        model.addConstr(
            gp.quicksum(x[i, j, p] for p in Products) <= JointCapacity[i, j],
            name=f"JointCapacity_{i}_{j}"
        )

    # Solve the model
    model.optimize()

    # Return results
    if model.status == GRB.OPTIMAL:
        total_cost = model.objVal
        shipment_plan = []
        for i, j, p in x.keys():
            if x[i, j, p].x > 0:
                shipment_plan.append((i, j, p, x[i, j, p].x))
        return total_cost, shipment_plan
    else:
        return None, None

# Example usage with the provided data
if __name__ == "__main__":
    # Input data
    Cities = ["A", "B"]
    Links = [("A", "B")]
    Products = ["Product1"]
    Supply = [[10], [0]]  # Supply[i][p] for city i and product p
    Demand = [[0], [10]]  # Demand[i][p] for city i and product p

    # Convert to dictionary format for clarity
    ShipmentCost = {("A", "B", "Product1"): 1}
    Capacity = {("A", "B", "Product1"): 10}
    JointCapacity = {("A", "B"): 10}

    # Solve the problem
    total_cost, shipment_plan = solve_transportation_problem(
        Cities, Links, Products, Supply, Demand, 
        ShipmentCost, Capacity, JointCapacity
    )

    # Output results
    if total_cost is not None:
        print(f"Optimal solution found. Total cost: {total_cost}")
        print("Shipping plan:")
        for i, j, p, units in shipment_plan:
            print(f"Ship {units} units of {p} from {i} to {j}")
    else:
        print("No optimal solution found.")
